<template>
  <div
    :id="idea.id"
    :class="`bubble level-${level}`"
    @contextmenu.prevent="
      $refs.p.focus();
      showMenu = true;
    "
  >
    <p
      ref="p"
      spellcheck="false"
      :contenteditable="editable"
      @blur="
        editContent(map, idea.id, $event);
        showMenu = false;
      "
    >
      {{ idea.content }}
    </p>
    <transition name="fade-top">
      <ul v-if="showMenu">
        <li
          @click="
            addSubBubble(map, idea.id);
            showMenu = false;
          "
        >
          <i class="fas fa-plus"></i>
          Add sub-bubble
        </li>
        <li
          v-if="idea.id != 1"
          style="color: red"
          @click="
            deleteBubble(map, idea.id);
            showMenu = false;
          "
        >
          <i class="fas fa-trash"> </i> Delete
        </li>
      </ul>
    </transition>
  </div>
</template>

<script>
export default {
  name: "bubble",
  props: ["idea", "level", "editable"],
  data() {
    return {
      map: this.$store.state.map,
      showMenu: false,
    };
  },
  methods: {
    addSubBubble(map, id) {
      this.$store.commit("increaseID");
      if (map[0].id == id) {
        map.push({ content: "New Cell", id: this.$store.state.LATEST_ID });
        return;
      }
      map.forEach((o) => {
        if (o.id === id) {
          map.splice(
            map.findIndex((c) => c.id === id),
            1,
            [o, { content: "New Cell", id: this.$store.state.LATEST_ID }]
          );
        } else if (Array.isArray(o)) {
          this.addSubBubble(o, id);
        }
      });
    },
    editContent(map, id, e) {
      map.forEach((o) => {
        if (o.id === id) {
          o.content = e.currentTarget.textContent;
        } else if (Array.isArray(o)) {
          this.editContent(o, id, e);
        }
      });
    },
    deleteBubble(map, id) {
      if (id == 1) return;
      map.forEach((o) => {
        if (map[0].id === id) {
          map.splice(0, map.length);
          this.$store.commit("clearEmpty");
        } else if (map.some((o) => o.id === id)) {
          map.splice(
            map.findIndex((r) => r.id === id),
            1
          );
        } else if (Array.isArray(o)) {
          this.deleteBubble(o, id);
        }
      });
    },
  },
};
</script>

<style lang="scss" scoped>
@use "../M/sass/m" as *;
.bubble {
  min-width: fit-content;
  margin: 10px 0;
  padding: 14px 20px;
  border-radius: 40px;
  background-color: rgb(214, 71, 71);
  display: inline-block;
  color: white;
  text-align: center;
  box-shadow: 0px 1px 2px 1px rgba(0, 0, 0, 0.4);
  $i: 0;
  @while ($i < 20) {
    &.level-#{$i} {
      background-color: darker("accent", calc($i * 7%));
      //   width: calc(100vw / (power(2, $i)));
    }
    $i: $i + 1;
    position: relative;
    p {
      margin: 0;
      outline: none;
      white-space: pre;
    }
    ul {
      list-style: none;
      z-index: 1;
      position: absolute;
      background: rgba(250, 250, 250, 0.96);
      color: rgb(43, 43, 43);
      top: 25%;
      left: 20%;
      display: grid;
      text-align: left;
      border-radius: 6px;
      padding: 0;
      box-shadow: 0px 1px 8px 1px rgba(0, 0, 0, 0.2);
      li {
        margin: 2px 0;
        padding: 16px 20px;
        font-weight: bold;
        font-size: 0.9em;
        cursor: pointer;
        white-space: pre;
        &:not(&:first-of-type) {
          border-top: 1px solid rgba(43, 43, 43, 0.4);
        }
        i {
          margin: 0 6px;
        }
      }
    }
  }
}
</style>
