<template>
  <div>
    <idea-container :ideas="JSON.stringify(map)" :level="0" editable="true" />
    <m-button @click="reset" type="danger">Reset</m-button>
  </div>
</template>

<script>
import ideaContainer from "../components/ideaContainer.vue";
import MButton from "../M/vue/MButton.vue";

export default {
  name: "Home",
  data() {
    return {
      // map1: [
      //   "المعادلات اللاخطية",
      //   ["معادلة وحيدة", ["نيوتن", "النقطة الثابتة", "تنصيف المجال"]],
      //   ["جملة معادلات", ["نيوتن", "غاوس سيدل", "غاوس جيكوبي"]],
      // ],
      map: this.$store.state.map,
    };
  },
  watch: {
    map: {
      deep: true,
      handler(newMap) {
        localStorage.setItem("map", JSON.stringify(newMap));
      },
    },
  },
  components: { ideaContainer, MButton },
  methods: {
    reset() {
      localStorage.setItem(
        "map",
        JSON.stringify([{ content: "Start", id: 1 }])
      );
      location.reload();
    },
  },
};
</script>
