<template>
  <button :class="`MBUTTON ${m}  ${type}`" @click.prevent>
    <i v-if="icon" :class="icon"></i>
    <span>
      <slot></slot>
    </span>
  </button>
</template>

<script>
export default {
  name: "MButton",
  props: ["type", "icon", "m"],
};
</script>

<style lang="scss" scoped>
@use "../sass/m" as *;

button {
  display: inline-block;
  margin: 4px;
  padding: 10px;
  font-weight: bold;
  font-size: 0.92rem;
  border: none;
  outline: none;
  border-radius: $ui_radius;
  cursor: pointer;
  transition: all 0.4s ease;
  &:hover {
    background: darker("accent", 20%);
    transform: scale(1.04);
  }
  @extend %m;
  @extend %semantic-colors;
  i {
    margin: 0 4px;
  }
}
</style>
